arguments.command:
set -euo pipefail
WS='/mnt/c/Users/Apinan/owen-workspace'
OCW='/home/apinan/.openclaw/workspace'
cd "$WS"
# 1) delete original protected source only; keep zip intact
rm -f -- "$WS/MODEL_FORMAT_LOCK.md"

# 2) replace stored password/code literal in editable memory/rule docs, excluding zip/quarantine/backup and protected deleted file
python3 - <<'PY'
from pathlib import Path
roots=[Path('/mnt/c/Users/Apinan/owen-workspace'), Path('/home/apinan/.openclaw/workspace')]
allowed_suffix={'.md','.txt'}
skip_parts={'.cleanup-backup','.cleanup-quarantine','node_modules','.git'}
changed=[]
for root in roots:
    if not root.exists():
        continue
    for p in root.rglob('*'):
        if not p.is_file() or p.suffix not in allowed_suffix:
            continue
        if any(part in skip_parts for part in p.parts):
            continue
        if p.name == 'MODEL_FORMAT_LOCK.md':
            continue
        try:
            s=p.read_text(encoding='utf-8')
        except UnicodeDecodeError:
            continue
        ns=s.replace('`Apinan`','`[аЄЦаЄ≤аЄ°аЄ£аЄЂаЄ±аЄ™аЄИаЄ≤аЄБаєАаЄИаєЙаЄ≤аЄЩаЄ≤аЄҐаєАаЄ°аЄЈаєИаЄ≠аЄИаЄ≥аєАаЄЫаєЗаЄЩ]`').replace('Apinan','[аЄЦаЄ≤аЄ°аЄ£аЄЂаЄ±аЄ™аЄИаЄ≤аЄБаєАаЄИаєЙаЄ≤аЄЩаЄ≤аЄҐаєАаЄ°аЄЈаєИаЄ≠аЄИаЄ≥аєАаЄЫаєЗаЄЩ]')
        if ns != s:
            p.write_text(ns, encoding='utf-8')
            changed.append(str(p))
print('changed_files=')
for x in changed:
    print(x)
PY

# 3) verify: source deleted, zip kept, no literal in active editable docs (excluding zip/quarantine/backup)
printf 'source_exists='; test -e "$WS/MODEL_FORMAT_LOCK.md" && echo yes || echo no
printf 'zip_exists='; test -e "$WS/MODEL_FORMAT_LOCK.md.zip" && echo yes || echo no
printf 'remaining_literal_count='; grep -RIl --exclude='*.zip' --exclude-dir='.cleanup-backup' --exclude-dir='.cleanup-quarantine' --exclude-dir='node_modules' --exclude-dir='.git' 'Apinan' "$WS" "$OCW" 2>/dev/null | wc -l
